kernel_src="""

#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelLogSoftmaxCustom {
public:
    __aicore__ inline KernelLogSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                int32_t dim)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        dim_ = dim;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue1_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue2_, 1, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Each block handles a contiguous chunk of rows.
        // Assume tensor is 2D with shape (batch, features). tileLen_ = features per row.
        // If tileLen_ < actual features (shouldn't happen in this design), we need outer handling.
        for (uint32_t row = blockIdx; row < totalLen_ / tileLen_; row += blockNum) {
            uint32_t base = row * tileLen_;
            uint32_t len = tileLen_;
            if (base + len > totalLen_) len = totalLen_ - base;
            if (len == 0) break;

            // Copy in x tile (one row)
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[base], len);
            inQueueX_.EnQue(xLocal);

            // Compute log softmax on this row
            AscendC::LocalTensor<float> xDeque = inQueueX_.DeQue<float>();
            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
            AscendC::LocalTensor<float> tmp1 = tmpQueue1_.AllocTensor<float>();
            AscendC::LocalTensor<float> tmp2 = tmpQueue2_.AllocTensor<float>();

            // Step 1: max over row
            float rowMax = 0.0f;
            AscendC::ReduceMax(rowMax, xDeque, len);

            // Step 2: subtract max, exp, sum
            AscendC::Subs(tmp1, xDeque, rowMax, len);
            AscendC::Exp(tmp1, tmp1, len);
            float sumExp = 0.0f;
            AscendC::ReduceSum(sumExp, tmp1, len);

            // Step 3: log(sumExp)
            float logSum = logf(sumExp);

            // Step 4: y = x - max - logSum = (x - max) - logSum, but careful: y = x - log( sum exp(x - max) ) - max
            // Actually: log softmax = x - max - log(sum(exp(x - max)))
            // So: subtract max, then subtract logSum
            AscendC::Subs(yLocal, xDeque, rowMax, len);
            AscendC::Subs(yLocal, yLocal, logSum, len);

            // Free temporary tensors
            tmpQueue1_.FreeTensor(tmp1);
            tmpQueue2_.FreeTensor(tmp2);
            inQueueX_.FreeTensor(xDeque);

            outQueueY_.EnQue<float>(yLocal);

            // Copy out y
            AscendC::LocalTensor<float> yDeque = outQueueY_.DeQue<float>();
            AscendC::DataCopy(yGm_[base], yDeque, len);
            outQueueY_.FreeTensor(yDeque);
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue1_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue2_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    int32_t dim_ {1};
};

extern "C" __global__ __aicore__ void log_softmax_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelLogSoftmaxCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength, tiling_data.dim);
    op.Process();
}
